solutions.javascript:
function isExposedPortMapped(dockerPorts, hostPorts) {
  if (dockerPorts.length !== hostPorts.length) {
    return false;
  }
  for (let i = 0; i < dockerPorts.length; i++) {
    let [hostPort, containerPort] = dockerPorts[i].split(':');
    if (hostPorts.indexOf(parseInt(hostPort)) === -1) {
      return false;
    }
  }
  return true;
}

var input = JSON.parse(process.stdin.readFileSync(0, 'utf-8'));
var dockerPorts = input.docker_ports;
var hostPorts = input.host_ports;
process.stdout.write(isExposedPortMapped(dockerPorts, hostPorts) + '\n');
